<div><header><p>ngafe.space</p><h1>Cari space-mu buat ngafe</h1><a class="ngafe-card" href="/cari">Cari cafe atau area</a></header><section><div style="display:flex;gap:8px;overflow:auto;margin:16px 0">@foreach($categories->take(6) as $category)<a class="ngafe-chip" href="/cari?categories[]={{ $category->slug }}">{{ $category->name }}</a>@endforeach<details><summary class="ngafe-chip">Lainnya</summary>@foreach($categories->skip(6) as $category)<a class="ngafe-chip" href="/cari?categories[]={{ $category->slug }}">{{ $category->name }}</a>@endforeach</details></div><h2>Lagi rame dibahas</h2><div class="ngafe-grid">@foreach($cafes as $cafe)<a class="ngafe-card" href="/{{ $cafe->city }}/{{ $cafe->slug }}">@if($cafe->photos->first())<img class="ngafe-photo" src="{{ $cafe->photos->first()->url_card }}" alt="">@else<div class="ngafe-photo"></div>@endif<h3>{{ $cafe->name }}</h3><p>{{ $cafe->rating_avg ? str_replace('.', ',', $cafe->rating_avg).' · '.$cafe->rating_count.' review' : 'Belum ada review' }}</p><p>{{ $cafe->categories->take(2)->pluck('name')->join(' · ') }}</p></a>@endforeach</div></section></div>
